"use client";


import React from "react";

import {
  Input,
  Label,
  Textarea,
  Checkbox,
  useToast,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  Badge,
  Alert,
  FormModal,
} from "@/shared/ui";
import type { Catalog, PriceGroup } from "@/features/products/types";
import type { Language } from "@/shared/types/internationalization";
import { useSaveCatalogMutation } from "@/features/products/hooks/useProductSettingsQueries";
import { logClientError } from "@/shared/utils/observability/client-error-logger";

interface CatalogModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
  catalog?: Catalog | null;
  languages: Language[];
  languagesLoading: boolean;
  languagesError: string | null;
  priceGroups: PriceGroup[];
  loadingGroups: boolean;
  defaultGroupId: string;
}

export function CatalogModal({
  isOpen,
  onClose,
  onSuccess,
  catalog,
  languages,
  languagesLoading,
  languagesError,
  priceGroups,
  loadingGroups,
  defaultGroupId,
}: CatalogModalProps): React.JSX.Element {
  const { toast } = useToast();
  const saveMutation = useSaveCatalogMutation();
  const [error, setError] = React.useState<string | null>(null);
  const [form, setForm] = React.useState({
    name: "",
    description: "",
    isDefault: false,
  });
  const [selectedLanguageIds, setSelectedLanguageIds] = React.useState<
    string[]
  >([]);
  const [defaultLanguageId, setDefaultLanguageId] = React.useState("");
  const [catalogPriceGroupIds, setCatalogPriceGroupIds] = React.useState<
    string[]
  >([]);
  const [catalogDefaultPriceGroupId, setCatalogDefaultPriceGroupId] =
    React.useState("");
  const [languageQuery, setLanguageQuery] = React.useState("");

  React.useEffect(() => {
    if (catalog) {
      setForm({
        name: catalog.name,
        description: catalog.description ?? "",
        isDefault: catalog.isDefault,
      });
      const nextLanguageIds = catalog.languageIds ?? [];
      setSelectedLanguageIds(nextLanguageIds);
      setDefaultLanguageId(
        catalog.defaultLanguageId ?? nextLanguageIds[0] ?? "",
      );
      const nextPriceGroupIds = catalog.priceGroupIds?.length
        ? catalog.priceGroupIds
        : defaultGroupId
          ? [defaultGroupId]
          : [];
      setCatalogPriceGroupIds(nextPriceGroupIds);
      setCatalogDefaultPriceGroupId(
        catalog.defaultPriceGroupId ??
          nextPriceGroupIds[0] ??
          defaultGroupId ??
          "",
      );
    } else {
      setForm({
        name: "",
        description: "",
        isDefault: false,
      });
      setSelectedLanguageIds([]);
      setDefaultLanguageId("");
      setCatalogPriceGroupIds(defaultGroupId ? [defaultGroupId] : []);
      setCatalogDefaultPriceGroupId(defaultGroupId ?? "");
    }
    setError(null);
    setLanguageQuery("");
  }, [catalog, defaultGroupId]);

  const handleSubmit = async (): Promise<void> => {
    if (saveMutation.isPending) return;
    const name = form.name.trim();
    if (!name) {
      toast("Catalog name is required.", { variant: "error" });
      return;
    }
    if (selectedLanguageIds.length === 0) {
      toast("Select at least one language.", { variant: "error" });
      return;
    }
    if (
      !defaultLanguageId ||
      !selectedLanguageIds.includes(defaultLanguageId)
    ) {
      toast("Select a default language.", { variant: "error" });
      return;
    }
    if (catalogPriceGroupIds.length === 0) {
      toast("Select at least one price group.", { variant: "error" });
      return;
    }
    if (
      !catalogDefaultPriceGroupId ||
      !catalogPriceGroupIds.includes(catalogDefaultPriceGroupId)
    ) {
      toast("Select a default price group.", { variant: "error" });
      return;
    }

    try {
      await saveMutation.mutateAsync({
        ...(catalog?.id ? { id: catalog.id } : {}),
        data: {
          name,
          description: form.description.trim(),
          languageIds: selectedLanguageIds,
          defaultLanguageId,
          priceGroupIds: catalogPriceGroupIds,
          defaultPriceGroupId: catalogDefaultPriceGroupId,
          isDefault: form.isDefault,
        },
      });

      toast("Catalog saved.", { variant: "success" });
      onSuccess();
    } catch (err) {
      logClientError(err, { context: { source: "CatalogModal", action: "saveCatalog", catalogId: catalog?.id } });
      setError(err instanceof Error ? err.message : "Failed to save catalog.");
    }
  };

  const availableLanguages = React.useMemo((): Language[] => {
    const query = languageQuery.trim().toLowerCase();
    return languages.filter(
      (l) =>
        !selectedLanguageIds.includes(l.id) &&
        (!query ||
          l.name.toLowerCase().includes(query) ||
          l.code.toLowerCase().includes(query)),
    );
  }, [languages, selectedLanguageIds, languageQuery]);

  const toggleLanguage = (id: string): void => {
    setSelectedLanguageIds((prev) => {
      const next = prev.includes(id)
        ? prev.filter((i) => i !== id)
        : [...prev, id];
      if (!next.includes(defaultLanguageId))
        setDefaultLanguageId(next[0] ?? "");
      return next;
    });
  };

  const moveLanguage = (id: string, direction: "up" | "down"): void => {
    setSelectedLanguageIds((prev) => {
      const idx = prev.indexOf(id);
      if (idx === -1) return prev;
      const nextIdx = direction === "up" ? idx - 1 : idx + 1;
      if (nextIdx < 0 || nextIdx >= prev.length) return prev;
      const next = [...prev];
      [next[idx], next[nextIdx]] = [next[nextIdx]!, next[idx]!];
      return next;
    });
  };

  const togglePriceGroup = (id: string): void => {
    setCatalogPriceGroupIds((prev) => {
      const next = prev.includes(id)
        ? prev.filter((i) => i !== id)
        : [...prev, id];
      if (!next.includes(catalogDefaultPriceGroupId))
        setCatalogDefaultPriceGroupId(next[0] ?? "");
      return next;
    });
  };

  return (
    <FormModal
      isOpen={isOpen}
      onClose={onClose}
      title={catalog ? "Edit Catalog" : "Create Catalog"}
      onSave={() => {
        void handleSubmit();
      }}
      isSaving={saveMutation.isPending}
      saveText={catalog ? "Update" : "Create"}
      cancelText="Close"
      size="lg"
    >
      <div className="space-y-6">
        {error && (
          <Alert variant="error" className="p-3 text-xs">
            {error}
          </Alert>
        )}

        <div className="grid gap-4">
          <div className="space-y-2">
            <Label htmlFor="catalog-name">Name</Label>
            <Input
              id="catalog-name"
              value={form.name}
              onChange={(e) =>
                setForm((p) => ({ ...p, name: e.target.value }))
              }
              placeholder="e.g. Main Store"
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="catalog-desc">Description</Label>
            <Textarea
              id="catalog-desc"
              value={form.description}
              onChange={(e) =>
                setForm((p) => ({ ...p, description: e.target.value }))
              }
              placeholder="Optional description..."
              rows={2}
            />
          </div>
          <Label className="flex items-center gap-2 text-gray-300">
            <Checkbox
              checked={form.isDefault}
              onCheckedChange={(v) =>
                setForm((p) => ({ ...p, isDefault: Boolean(v) }))
              }
            />
            Set as default catalog
          </Label>
        </div>

        <div className="rounded-md border border-border bg-card/70 p-4 space-y-4">
          <Label className="text-sm font-semibold text-white">
            Languages
          </Label>
          {languagesLoading ? (
            <p className="text-xs text-gray-500">Loading languages...</p>
          ) : languagesError ? (
            <p className="text-xs text-red-400">{languagesError}</p>
          ) : (
            <div className="space-y-4">
              <Input
                placeholder="Search languages..."
                value={languageQuery}
                onChange={(e) => setLanguageQuery(e.target.value)}
              />

              <div className="space-y-1">
                {selectedLanguageIds.length === 0 ? (
                  <p className="text-xs text-gray-500">
                    No languages selected.
                  </p>
                ) : (
                  selectedLanguageIds.map((id, index) => {
                    const lang = languages.find((l) => l.id === id);
                    if (!lang) return null;
                    return (
                      <div
                        key={id}
                        className="flex items-center justify-between rounded-md border bg-gray-900 px-3 py-1.5 text-xs text-gray-200"
                      >
                        <div className="flex items-center gap-2">
                          <span className="text-gray-500 w-4">
                            {index + 1}.
                          </span>
                          <span>
                            {lang.name} ({lang.code})
                          </span>
                          {id === defaultLanguageId && (
                            <Badge variant="success">
                              Default
                            </Badge>
                          )}
                        </div>
                        <div className="flex gap-1">
                          <Button
                            variant="ghost"
                            size="icon"
                            className="h-6 w-6"
                            onClick={() => moveLanguage(id, "up")}
                            disabled={index === 0}
                          >
                            ↑
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            className="h-6 w-6"
                            onClick={() => moveLanguage(id, "down")}
                            disabled={
                              index === selectedLanguageIds.length - 1
                            }
                          >
                            ↓
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            className="h-6 w-6 text-red-400"
                            onClick={() => toggleLanguage(id)}
                          >
                            ×
                          </Button>
                        </div>
                      </div>
                    );
                  })
                )}
              </div>

              <div className="max-h-32 overflow-y-auto rounded-md border border-border bg-gray-900 p-2 text-xs">
                {availableLanguages.map((lang) => (
                  <Button
                    key={lang.id}
                    variant="ghost"
                    className="w-full justify-between h-8 px-2"
                    onClick={() => toggleLanguage(lang.id)}
                  >
                    <span>
                      {lang.name} ({lang.code})
                    </span>
                    <span className="text-gray-500">Add</span>
                  </Button>
                ))}
              </div>

              <div className="space-y-2">
                <Label className="text-xs text-gray-400">
                  Default language
                </Label>
                <Select
                  value={defaultLanguageId}
                  onValueChange={(v) => setDefaultLanguageId(v)}
                  disabled={selectedLanguageIds.length === 0}
                >
                  <SelectTrigger className="w-full bg-gray-900 border-border text-xs text-white">
                    <SelectValue placeholder="Select default language" />
                  </SelectTrigger>
                  <SelectContent>
                    {selectedLanguageIds.map((id) => {
                      const lang = languages.find((l) => l.id === id);
                      return (
                        <SelectItem key={id} value={id}>
                          {lang?.name} ({lang?.code})
                        </SelectItem>
                      );
                    })}
                  </SelectContent>
                </Select>
              </div>
            </div>
          )}
        </div>

        <div className="rounded-md border border-border bg-card/70 p-4 space-y-4">
          <Label className="text-sm font-semibold text-white">
            Price Groups
          </Label>
          {loadingGroups ? (
            <p className="text-xs text-gray-500">Loading groups...</p>
          ) : (
            <div className="space-y-4">
              <div className="flex flex-wrap gap-2">
                {catalogPriceGroupIds.map((id) => {
                  const group = priceGroups.find((g) => g.id === id);
                  return (
                    <Button
                      key={id}
                      variant="secondary"
                      className="h-7 rounded-full px-3 text-xs"
                      onClick={() => togglePriceGroup(id)}
                    >
                      {group?.name ?? id}{" "}
                      <span className="ml-1 text-gray-500">×</span>
                    </Button>
                  );
                })}
              </div>

              <div className="max-h-32 overflow-y-auto rounded-md border border-border bg-gray-900 p-2 text-xs">
                {priceGroups.map((group) => (
                  <Button
                    key={group.id}
                    variant="ghost"
                    className="w-full justify-between h-8 px-2"
                    onClick={() => togglePriceGroup(group.id)}
                  >
                    <span>
                      {group.name} ({group.currencyCode})
                    </span>
                    <span>
                      {catalogPriceGroupIds.includes(group.id)
                        ? "Remove"
                        : "Add"}
                    </span>
                  </Button>
                ))}
              </div>

              <div className="space-y-2">
                <Label className="text-xs text-gray-400">
                  Default price group
                </Label>
                <Select
                  value={catalogDefaultPriceGroupId}
                  onValueChange={(v) =>
                    setCatalogDefaultPriceGroupId(v)
                  }
                  disabled={catalogPriceGroupIds.length === 0}
                >
                  <SelectTrigger className="w-full bg-gray-900 border-border text-xs text-white">
                    <SelectValue placeholder="Select default price group" />
                  </SelectTrigger>
                  <SelectContent>
                    {catalogPriceGroupIds.map((id) => {
                      const group = priceGroups.find((g) => g.id === id);
                      return (
                        <SelectItem key={id} value={id}>
                          {group?.name}
                        </SelectItem>
                      );
                    })}
                  </SelectContent>
                </Select>
              </div>
            </div>
          )}
        </div>
      </div>
    </FormModal>
  );
}

"use client";

import { useState, useRef, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { logger } from "@/shared/utils/logger";
import type { Catalog } from "@/features/products/types";
import type { PriceGroupWithDetails } from "@/features/products/types";

type LanguageRecord = { id: string; code: string; name: string };
type LanguageOption = {
  value: "name_en" | "name_pl" | "name_de";
  label: string;
};
type CurrencyRecord = { code?: string | null };

const supportedLanguageMap: Record<string, LanguageOption> = {
  EN: { value: "name_en", label: "English" },
  PL: { value: "name_pl", label: "Polish" },
  DE: { value: "name_de", label: "German" },
};

// Query keys for cache management
const catalogSyncQueryKeys = {
  catalogs: ["catalogs"] as const,
  priceGroups: ["price-groups"] as const,
  languages: ["languages"] as const,
  currencies: ["currencies"] as const,
};

// API fetch functions
async function fetchCatalogs(): Promise<Catalog[]> {
  const res = await fetch("/api/catalogs");
  if (!res.ok) {
    const payload = (await res.json()) as { error?: string };
    throw new Error(payload?.error || "Failed to load catalogs");
  }
  return res.json() as Promise<Catalog[]>;
}

async function fetchPriceGroups(): Promise<PriceGroupWithDetails[]> {
  const res = await fetch("/api/price-groups");
  if (!res.ok) {
    throw new Error("Failed to load price groups");
  }
  return res.json() as Promise<PriceGroupWithDetails[]>;
}

async function fetchLanguages(): Promise<LanguageRecord[]> {
  const res = await fetch("/api/languages");
  if (!res.ok) {
    throw new Error("Failed to load languages");
  }
  return res.json() as Promise<LanguageRecord[]>;
}

async function fetchCurrencies(): Promise<CurrencyRecord[]> {
  const res = await fetch("/api/currencies");
  if (!res.ok) {
    throw new Error("Failed to load currencies");
  }
  return res.json() as Promise<CurrencyRecord[]>;
}

export function useCatalogSync(catalogFilter: string): { catalogs: Catalog[]; catalogsLoading: boolean; catalogsError: string | null; currencyCode: string; setCurrencyCode: (action: string | ((prev: string) => string)) => void; currencyOptions: string[]; priceGroups: PriceGroupWithDetails[]; catalogFilterInitialized: React.MutableRefObject<boolean>; languageOptions: LanguageOption[]; fallbackNameLocale: "name_en" | "name_pl" | "name_de" | undefined; } {
  const catalogFilterInitialized = useRef(false);

  // Parallel queries for all data sources
  const catalogsQuery = useQuery({
    queryKey: catalogSyncQueryKeys.catalogs,
    queryFn: fetchCatalogs,
    staleTime: 1000 * 60 * 5, // 5 minutes
  });

  const priceGroupsQuery = useQuery({
    queryKey: catalogSyncQueryKeys.priceGroups,
    queryFn: fetchPriceGroups,
    staleTime: 1000 * 60 * 5,
  });

  const languagesQuery = useQuery({
    queryKey: catalogSyncQueryKeys.languages,
    queryFn: fetchLanguages,
    staleTime: 1000 * 60 * 5,
  });

  const currenciesQuery = useQuery({
    queryKey: catalogSyncQueryKeys.currencies,
    queryFn: fetchCurrencies,
    staleTime: 1000 * 60 * 5,
  });

  // Log errors
  if (catalogsQuery.error) {
    logger.error("Failed to load catalogs:", catalogsQuery.error);
  }
  if (priceGroupsQuery.error) {
    logger.error("Failed to load price groups:", priceGroupsQuery.error);
  }
  if (languagesQuery.error) {
    logger.error("Failed to load languages:", languagesQuery.error);
  }
  if (currenciesQuery.error) {
    logger.error("Failed to load currencies:", currenciesQuery.error);
  }

  // Extract data with defaults
  const rawCatalogs = useMemo(
    () => catalogsQuery.data ?? [],
    [catalogsQuery.data],
  );
  const priceGroups = useMemo(
    () => priceGroupsQuery.data ?? [],
    [priceGroupsQuery.data],
  );
  const languages = useMemo(
    () => languagesQuery.data ?? [],
    [languagesQuery.data],
  );
  const currencyPriceGroups = priceGroups;

  // Compute allowed currency codes
  const allowedCurrencyCodes = useMemo(() => {
    const data = currenciesQuery.data ?? [];
    return data
      .map((entry) => entry.code?.trim().toUpperCase())
      .filter((code): code is string => Boolean(code));
  }, [currenciesQuery.data]);

  // Memoize catalog transformation to prevent new references
  const catalogs = useMemo(
    () =>
      rawCatalogs.map((catalog) => ({
        ...catalog,
        priceGroupIds: catalog.priceGroupIds ?? [],
        defaultPriceGroupId: catalog.defaultPriceGroupId ?? null,
      })),
    [rawCatalogs],
  );

  // Memoize currency options to prevent unnecessary re-renders
  const { codes, fallbackCode } = useMemo((): { codes: string[]; fallbackCode: string } => {
    if (currencyPriceGroups.length === 0)
      return { codes: [] as string[], fallbackCode: "" };

    const isCatalogScoped =
      catalogFilter !== "all" && catalogFilter !== "unassigned";
    const catalog = isCatalogScoped
      ? catalogs.find((entry) => entry.id === catalogFilter)
      : undefined;
    const catalogPriceGroupIds = catalog?.priceGroupIds ?? [];
    const allowedGroupIds =
      catalogPriceGroupIds.length > 0 ? new Set(catalogPriceGroupIds) : null;

    const candidateGroups = allowedGroupIds
      ? currencyPriceGroups.filter((group) => allowedGroupIds.has(group.id))
      : currencyPriceGroups;

    let codes = Array.from(
      new Set(
        candidateGroups
          .map((group) => group.currency?.code)
          .filter((code): code is NonNullable<typeof code> => Boolean(code)),
      ),
    ).map((code) => code.trim().toUpperCase());

    const allowedSet = new Set(
      allowedCurrencyCodes.map((code) => code.trim().toUpperCase()),
    );
    if (allowedSet.size > 0) {
      codes = codes.filter((code) => allowedSet.has(code));
    } else {
      // Basic safety filter if no allowed list available.
      codes = codes.filter((code) => /^[A-Z]{3,5}$/.test(code));
    }

    const defaultGroupId = catalog?.defaultPriceGroupId ?? null;
    const defaultGroup = defaultGroupId
      ? candidateGroups.find((group) => group.id === defaultGroupId)
      : candidateGroups.find((group) => group.isDefault);

    const fallbackCode = defaultGroup?.currency?.code || codes[0] || "";

    return { codes, fallbackCode };
  }, [catalogFilter, catalogs, currencyPriceGroups, allowedCurrencyCodes]);

  // Sync Currency Options based on Catalog
  const currencyOptions = codes;

  // Derived state for currencyCode to avoid set-state-in-effect
  // If the current user selection is valid for the current catalog, keep it.
  // Otherwise, fallback to the catalog's default.
  // We use a piece of state to track the user's *explicit* selection if any.
  // Note: We use 'currencyCode' state here to track the *effective* code if possible,
  // but to match the "derived" pattern we need to know if the state value is "stale".
  // Actually, the simplest way is to just let the user set a preference, and validate it on read.
  const [userCurrencyCode, setUserCurrencyCode] = useState<string | null>(null);

  const currencyCode =
    userCurrencyCode && codes.includes(userCurrencyCode)
      ? userCurrencyCode
      : fallbackCode;

  const setCurrencyCode = (action: string | ((prev: string) => string)) => {
    // Wrap the setter to handle functional updates correctly with the derived value
    if (typeof action === "function") {
      setUserCurrencyCode((_prev) => {
        // We use the *derived* currencyCode as the base for the update
        const newVal = action(currencyCode);
        return newVal;
      });
    } else {
      setUserCurrencyCode(action);
    }
  };

  const { languageOptions, fallbackNameLocale } = useMemo((): { languageOptions: LanguageOption[]; fallbackNameLocale: "name_en" | "name_pl" | "name_de" | undefined } => {
    const options: LanguageOption[] = [];
    const isCatalogScoped =
      catalogFilter !== "all" && catalogFilter !== "unassigned";
    const catalog = isCatalogScoped
      ? catalogs.find((entry) => entry.id === catalogFilter)
      : undefined;
    const allowedIds = catalog?.languageIds ?? [];

    const scopedLanguages =
      allowedIds.length > 0
        ? languages.filter((lang) => allowedIds.includes(lang.id))
        : languages;

    const seen = new Set<string>();
    scopedLanguages.forEach((lang) => {
      const key = lang.code?.trim().toUpperCase();
      const option = supportedLanguageMap[key];
      if (!option || seen.has(option.value)) return;
      seen.add(option.value);
      options.push(option);
    });

    if (options.length === 0) {
      options.push(supportedLanguageMap.EN!);
      options.push(supportedLanguageMap.PL!);
      options.push(supportedLanguageMap.DE!);
    }

    const defaultLanguageId = catalog?.defaultLanguageId ?? null;
    const defaultLang = defaultLanguageId
      ? languages.find((lang) => lang.id === defaultLanguageId)
      : null;
    const defaultOption = defaultLang
      ? supportedLanguageMap[defaultLang.code?.trim().toUpperCase() || ""]
      : undefined;
    const fallbackNameLocale = defaultOption?.value ?? options[0]?.value;

    return { languageOptions: options, fallbackNameLocale };
  }, [catalogFilter, catalogs, languages]);

  return {
    catalogs,
    catalogsLoading: catalogsQuery.isLoading,
    catalogsError: catalogsQuery.error ? catalogsQuery.error.message : null,
    currencyCode,
    setCurrencyCode,
    currencyOptions,
    priceGroups,
    catalogFilterInitialized,
    languageOptions,
    fallbackNameLocale,
  };
}

"use client";

import { useNormalizedQuery, useComposedQuery } from "@/shared/hooks/useQueryComposition";
import { useQueryScheduler, useBackgroundQueries } from "@/shared/hooks/useQueryScheduler";
import { useAdaptiveQuery } from "@/shared/hooks/query/useSmartCache";
import { useEffect } from "react";

// Enhanced product queries with normalization and composition
export function useEnhancedProducts(): ReturnType<typeof useNormalizedQuery> {
  const scheduler = useQueryScheduler();

  // Normalized products query
  const productsQuery = useNormalizedQuery(
    ['products', 'enhanced'],
    async (): Promise<any[]> => {
      const res = await fetch('/api/products');
      return res.json() as Promise<any[]>;
    }
  );

  // Composed query for product statistics
  const productStats = useComposedQuery(
    {
      queryKey: ['products', 'enhanced'],
      queryFn: async (): Promise<any[]> => {
        const res = await fetch('/api/products');
        return res.json() as Promise<any[]>;
      },
    },
    (products: any[]): { total: number; published: number; categories: number; avgPrice: number; } => ({
      total: products.length,
      published: products.filter((p: any) => p.published).length,
      categories: [...new Set(products.map((p: any) => p.category))].length,
      avgPrice: products.reduce((sum: number, p: any) => sum + (p.price || 0), 0) / products.length,
    })
  );

  // Schedule related queries
  useEffect(() => {
    scheduler.scheduleQuery(
      'product-categories',
      ['products', 'categories'],
      async () => {
        const catalogsRes = await fetch("/api/catalogs");
        if (!catalogsRes.ok) return [];
        const catalogs = (await catalogsRes.json()) as Array<{ id?: string }>;
        const catalogId = Array.isArray(catalogs) ? catalogs[0]?.id : undefined;
        if (!catalogId) return [];
        const res = await fetch(
          `/api/products/categories?catalogId=${encodeURIComponent(catalogId)}`
        );
        if (!res.ok) return [];
        return res.json();
      },
      { priority: 'medium', delay: 2000 }
    );

    scheduler.scheduleQuery(
      'product-tags',
      ['products', 'tags'],
      async () => {
        const res = await fetch('/api/products/tags');
        return res.json();
      },
      { priority: 'low', delay: 5000 }
    );
  }, [scheduler]);

  // Background sync for critical data
  useBackgroundQueries([
    {
      queryKey: ['products', 'count'],
      queryFn: async () => {
        const res = await fetch('/api/products/count');
        return res.json();
      },
      interval: 60000, // 1 minute
    },
  ]);

  return {
    products: productsQuery,
    stats: productStats,
